Bash(php artisan tinker --no-interaction 2>/dev/null << 'EOF'
// Check sessions table
use Illuminate\\Support\\Facades\\DB;
$sessions = DB::table\('sessions'\)->get\(\);
echo "Sessions count: " . $sessions->count\(\) . "\\n";
foreach \($sessions->take\(3\) as $s\) {
    $data = @unserialize\(base64_decode\($s->payload\)\);
    echo "Session ID: " . substr\($s->id, 0, 15\) . "...\\n";
    echo "Has _token: " . \(isset\($data['_token']\) ? 'YES' : 'NO'\) . "\\n";
    if \(isset\($data['_token']\)\) {
        echo "_token: " . substr\($data['_token'], 0, 10\) . "...\\n";
    }
    echo "Keys: " . implode\(', ', array_keys\($data ?: []\)\) . "\\n\\n";
}
EOF)

